     1→/**
     2→ * Centralized Path Resolution
     3→ *
     4→ * Handles environment variable expansion for portable PAI configuration.
     5→ * Claude Code doesn't expand $HOME in settings.json env values, so we do it here.
     6→ *
     7→ * Usage:
     8→ *   import { getPaiDir, getSettingsPath } from './lib/paths';
     9→ *   const paiDir = getPaiDir(); // Always returns expanded absolute path
    10→ */
    11→
    12→import { homedir } from 'os';
    13→import { join } from 'path';
    14→
    15→/**
    16→ * Expand shell variables in a path string
    17→ * Supports: $HOME, ${HOME}, ~
    18→ */
    19→export function expandPath(path: string): string {
    20→  const home = homedir();
    21→
    22→  return path
    23→    .replace(/^\$HOME(?=\/|$)/, home)
    24→    .replace(/^\$\{HOME\}(?=\/|$)/, home)
    25→    .replace(/^~(?=\/|$)/, home);
    26→}
    27→
    28→/**
    29→ * Get the PAI directory (expanded)
    30→ * Priority: PAI_DIR env var (expanded) → ~/.claude
    31→ */
    32→export function getPaiDir(): string {
    33→  const envPaiDir = process.env.PAI_DIR;
    34→
    35→  if (envPaiDir) {
    36→    return expandPath(envPaiDir);
    37→  }
    38→
    39→  return join(homedir(), '.claude');
    40→}
    41→
    42→/**
    43→ * Get the settings.json path
    44→ */
    45→export function getSettingsPath(): string {
    46→  return join(getPaiDir(), 'settings.json');
    47→}
    48→
    49→/**
    50→ * Get a path relative to PAI_DIR
    51→ */
    52→export function paiPath(...segments: string[]): string {
    53→  return join(getPaiDir(), ...segments);
    54→}
    55→
    56→/**
    57→ * Get the hooks directory
    58→ */
    59→export function getHooksDir(): string {
    60→  return paiPath('hooks');
    61→}
    62→
    63→/**
    64→ * Get the skills directory
    65→ */
    66→export function getSkillsDir(): string {
    67→  return paiPath('skills');
    68→}
    69→
    70→/**
    71→ * Get the MEMORY directory
    72→ */
    73→export function getMemoryDir(): string {
    74→  return paiPath('MEMORY');
    75→}
    76→

