     1→#!/usr/bin/env bun
     2→/**
     3→ * LoadContext.hook.ts - Inject PAI context into Claude's Context (SessionStart)
     4→ *
     5→ * PURPOSE:
     6→ * The foundational context injection hook. Reads the PAI SKILL.md plus
     7→ * AI Steering Rules (SYSTEM and USER) and outputs them as a <system-reminder>
     8→ * to stdout.
     9→ *
    10→ * TRIGGER: SessionStart
    11→ *
    12→ * INPUT:
    13→ * - Environment: PAI_DIR, TIME_ZONE
    14→ * - Files: skills/PAI/SKILL.md, skills/PAI/SYSTEM/AISTEERINGRULES.md,
    15→ *          skills/PAI/USER/AISTEERINGRULES.md, MEMORY/STATE/progress/*.json
    16→ *
    17→ * OUTPUT:
    18→ * - stdout: <system-reminder> containing SKILL.md + AI Steering Rules
    19→ * - stdout: Active work summary if previous sessions have pending work
    20→ * - stderr: Status messages and errors
    21→ * - exit(0): Normal completion
    22→ * - exit(1): Critical failure (SKILL.md not found)
    23→ *
    24→ * DESIGN PHILOSOPHY:
    25→ * Load SKILL.md and AI Steering Rules at session start. These are critical for
    26→ * consistent behavior. Other context (USER docs, SYSTEM docs) loads dynamically
    27→ * based on the Context Loading section in SKILL.md.
    28→ *
    29→ * ERROR HANDLING:
    30→ * - Missing SKILL.md: Fatal error, exits with code 1
    31→ * - Missing steering rules: Logged warning, continues (non-fatal)
    32→ * - Progress file errors: Logged, continues (non-fatal)
    33→ * - Date command failure: Falls back to ISO timestamp
    34→ *
    35→ * PERFORMANCE:
    36→ * - Blocking: Yes (context is essential)
    37→ * - Typical execution: <50ms
    38→ * - Skipped for subagents: Yes (they get context differently)
    39→ */
    40→
    41→import { readFileSync, existsSync, readdirSync, writeFileSync } from 'fs';
    42→import { join } from 'path';
    43→import { execSync } from 'child_process';
    44→import { getPaiDir } from './lib/paths';
    45→import { recordSessionStart } from './lib/notifications';
    46→
    47→/**
    48→ * Reset tab title to clean state at session start.
    49→ * Prevents stale tab titles from previous sessions bleeding through.
    50→ * Uses Kitty remote control to set a neutral title immediately.
    51→ */
    52→function resetTabTitle(paiDir: string): void {
    53→  const cleanTitle = 'New Session';
    54→  const stateFile = join(paiDir, 'MEMORY', 'STATE', 'tab-title.json');
    55→
    56→  try {
    57→    // Reset Kitty tab title immediately
    58→    const isKitty = process.env.TERM === 'xterm-kitty' || process.env.KITTY_LISTEN_ON;
    59→    if (isKitty) {
    60→      execSync(`kitty @ set-tab-title "${cleanTitle}"`, { stdio: 'ignore', timeout: 2000 });
    61→      // Reset tab color to default (dark blue for active, no special color for inactive)
    62→      execSync(
    63→        `kitten @ set-tab-color --self active_bg=#002B80 active_fg=#FFFFFF inactive_bg=none inactive_fg=#A0A0A0`,
    64→        { stdio: 'ignore', timeout: 2000 }
    65→      );
    66→      console.error('🔄 Tab title reset to clean state');
    67→    }
    68→
    69→    // Reset state file to prevent any stale data
    70→    const cleanState = {
    71→      title: cleanTitle,
    72→      rawTitle: cleanTitle,
    73→      timestamp: new Date().toISOString(),
    74→      state: 'idle'
    75→    };
    76→    writeFileSync(stateFile, JSON.stringify(cleanState, null, 2));
    77→    console.error('🔄 Tab state file reset');
    78→  } catch (err) {
    79→    console.error(`⚠️ Failed to reset tab title: ${err}`);
    80→    // Non-fatal, continue with session
    81→  }
    82→}
    83→
    84→async function getCurrentDate(): Promise<string> {
    85→  try {
    86→    const proc = Bun.spawn(['date', '+%Y-%m-%d %H:%M:%S %Z'], {
    87→      stdout: 'pipe',
    88→      env: { ...process.env, TZ: process.env.TIME_ZONE || 'America/Los_Angeles' }
    89→    });
    90→    const output = await new Response(proc.stdout).text();
    91→    return output.trim();
    92→  } catch (error) {
    93→    console.error('Failed to get current date:', error);
    94→    return new Date().toISOString();
    95→  }
    96→}
