   137→// ========================================
   138→// Types
   139→// ========================================
   140→
   141→interface HookInput {
   142→  session_id: string;
   143→  tool_name: string;
   144→  tool_input: Record<string, unknown> | string;
   145→}
   146→
   147→interface Pattern {
   148→  pattern: string;
   149→  reason: string;
   150→}
   151→
   152→interface PatternsConfig {
   153→  version: string;
   154→  philosophy: {
   155→    mode: string;
   156→    principle: string;
   157→  };
   158→  bash: {
   159→    blocked: Pattern[];
   160→    confirm: Pattern[];
   161→    alert: Pattern[];
   162→  };
   163→  paths: {
   164→    zeroAccess: string[];
   165→    readOnly: string[];
   166→    confirmWrite: string[];
   167→    noDelete: string[];
   168→  };
   169→  projects: Record<string, {
   170→    path: string;
   171→    rules: Array<{ action: string; reason: string }>;
   172→  }>;
