    62→    let data = '';
    63→    const timer = setTimeout(() => reject(new Error('Timeout')), timeout);
    64→    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
    65→    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
