     2→/**
     3→ * StartupGreeting.hook.ts - Display PAI Banner at Session Start (SessionStart)
     4→ *
     5→ * PURPOSE:
     6→ * Displays the responsive neofetch-style PAI banner with system statistics.
     7→ * Creates a visual confirmation that PAI is initialized and shows key metrics
     8→ * like skill count, session count, and learning items.
     9→ *
    10→ * TRIGGER: SessionStart
    11→ *
    12→ * INPUT:
    13→ * - Environment: COLUMNS, KITTY_WINDOW_ID for terminal detection
    14→ * - Settings: settings.json for identity configuration
    15→ *
    16→ * OUTPUT:
    17→ * - stdout: Banner display (captured by Claude Code)
    18→ * - stderr: Error messages on failure
    19→ * - exit(0): Normal completion
    20→ * - exit(1): Banner display failed
    21→ *
    22→ * SIDE EFFECTS:
    23→ * - Spawns Banner.ts tool as child process
    24→ * - Reads settings.json for configuration
    25→ *
    26→ * INTER-HOOK RELATIONSHIPS:
    27→ * - DEPENDS ON: None (runs independently at session start)
    28→ * - COORDINATES WITH: LoadContext (both run at SessionStart)
    29→ * - MUST RUN BEFORE: None (visual feedback only)
    30→ * - MUST RUN AFTER: None
    31→ *
    32→ * ERROR HANDLING:
    33→ * - Missing settings: Error logged, exits with error code
    34→ * - Banner tool failure: Error logged, exits with error code
    35→ *
    36→ * PERFORMANCE:
    37→ * - Non-blocking: Yes (banner is informational)
    38→ * - Typical execution: <100ms
    39→ * - Skipped for subagents: Yes
    40→ *
    41→ * BANNER MODES:
    42→ * - nano (<40 cols): Minimal single-line
    43→ * - micro (40-59 cols): Compact with stats
    44→ * - mini (60-84 cols): Medium layout
    45→ * - normal (85+ cols): Full neofetch-style
    46→ */
    47→
    48→import { readFileSync } from 'fs';
    49→import { join } from 'path';
    50→import { spawnSync, execSync } from 'child_process';
    51→
    52→import { getPaiDir, getSettingsPath } from './lib/paths';
    53→
    54→const paiDir = getPaiDir();
    55→const settingsPath = getSettingsPath();
    56→
    57→(async () => {
    58→  try {
    59→    const settings = JSON.parse(readFileSync(settingsPath, 'utf-8'));
    60→
    61→    // Check if this is a subagent session - if so, exit silently
    62→    const claudeProjectDir = process.env.CLAUDE_PROJECT_DIR || '';
    63→    const isSubagent = claudeProjectDir.includes('/.claude/Agents/') ||
    64→                      process.env.CLAUDE_AGENT_TYPE !== undefined;
    65→
    66→    if (isSubagent) {
    67→      process.exit(0);
    68→    }
    69→
    70→    // Run the banner tool
    71→    const bannerPath = join(paiDir, 'skills/PAI/Tools/Banner.ts');
    72→    const result = spawnSync('bun', ['run', bannerPath], {
    73→      encoding: 'utf-8',
    74→      stdio: ['inherit', 'pipe', 'pipe'],
    75→      env: {
    76→        ...process.env,
    77→        // Pass through terminal detection env vars
    78→        COLUMNS: process.env.COLUMNS,
    79→        KITTY_WINDOW_ID: process.env.KITTY_WINDOW_ID,
    80→      }
    81→    });
    82→
    83→    if (result.stdout) {
    84→      console.log(result.stdout);
    85→    }
    86→
    87→    // Send voice notification for startup greeting (fire-and-forget, non-blocking)
    88→    const voiceId = settings.daidentity?.voiceId || 's3TPKV1kjDlVtZbl4Ksh';
    89→    const voiceSettings = settings.daidentity?.voice;
    90→
    91→    // Use AbortController with short timeout to prevent hanging
    92→    const controller = new AbortController();
    93→    const timeoutId = setTimeout(() => controller.abort(), 1000); // 1s max
    94→
    95→    fetch('http://localhost:8888/notify', {
    96→      method: 'POST',
    97→      headers: { 'Content-Type': 'application/json' },
    98→      signal: controller.signal,
    99→      body: JSON.stringify({
